import React, { useState, useEffect } from 'react';
import { fetchWords, addWord, removeWord } from '../services/wordService';

/**
 * WordManager: 단어 입력 및 목록 표시를 담당하는 UI 컴포넌트입니다.
 */
const WordManager = () => {
    const [words, setWords] = useState([]);
    const [form, setForm] = useState({ word: '', meaning: '', difficulty: 'Easy', example: '' });

    useEffect(() => {
        loadWords();
    }, []);

    const loadWords = async () => {
        const data = await fetchWords();
        setWords(data);
    };

    const handleAdd = async (e) => {
        e.preventDefault();
        await addWord(form);
        setForm({ word: '', meaning: '', difficulty: 'Easy', example: '' });
        loadWords();
    };

    const handleDelete = async (id) => {
        if (window.confirm("삭제하시겠습니까?")) {
            await removeWord(id);
            loadWords();
        }
    };

    return (
        <div className="word-container" style={{ padding: '20px', background: '#fff' }}>
            <h2>Word Tower: Admin Page</h2>
            <form onSubmit={handleAdd} style={{ marginBottom: '20px' }}>
                <input placeholder="Word" value={form.word} onChange={e => setForm({...form, word: e.target.value})} required />
                <input placeholder="Meaning" value={form.meaning} onChange={e => setForm({...form, meaning: e.target.value})} required />
                <select value={form.difficulty} onChange={e => setForm({...form, difficulty: e.target.value})}>
                    <option value="Easy">Easy</option>
                    <option value="Medium">Medium</option>
                    <option value="Hard">Hard</option>
                </select>
                <input placeholder="Example" value={form.example} onChange={e => setForm({...form, example: e.target.value})} />
                <button type="submit">Add Word</button>
            </form>

            <table style={{ width: '100%', borderCollapse: 'collapse' }} border="1">
                <thead>
                    <tr>
                        <th>ID</th><th>Word</th><th>Meaning</th><th>Level</th><th>Example</th><th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    {words.map(w => (
                        <tr key={w.id}>
                            <td>{w.id}</td>
                            <td>{w.word}</td>
                            <td>{w.meaning}</td>
                            <td>{w.difficulty}</td>
                            <td>{w.example}</td>
                            <td><button onClick={() => handleDelete(w.id)}>Delete</button></td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default WordManager;
